239		} else if !strings.EqualFold(n.Namespace, defaultNamespace) {
240			sb.WriteString(n.Namespace)
241			sb.WriteByte('/')
242		}
243	
244		// always include model and tag
245		sb.WriteString(n.Model)
246		sb.WriteString(":")
247		sb.WriteString(n.Tag)
248		return sb.String()
249	}
250	
251	// IsValidNamespace reports whether the provided string is a valid
252	// namespace.
253	func IsValidNamespace(s string) bool {
254		return isValidPart(kindNamespace, s)
255	}
256	
257	// IsValid reports whether all parts of the name are present and valid. The
258	// digest is a special case, and is checked for validity only if present.
259	//
260	// Note: The digest check has been removed as is planned to be added back in
261	// at a later time.
262	func (n Name) IsValid() bool {
263		return n.IsFullyQualified()
264	}
265	
266	// IsFullyQualified returns true if all parts of the name are present and
267	// valid without the digest.
268	func (n Name) IsFullyQualified() bool {
269		parts := []string{
270			n.Host,
271			n.Namespace,
272			n.Model,
273			n.Tag,
274		}
275		for i, part := range parts {
276			if !isValidPart(partKind(i), part) {
277				return false
278			}
279		}
280		return true
281	}
282	
283	// Filepath returns a canonical filepath that represents the name with each part from
284	// host to tag as a directory in the form:
285	//
286	//	{host}/{namespace}/{model}/{tag}
287	//
288	// It uses the system's filepath separator and ensures the path is clean.
289	//
290	// It panics if the name is not fully qualified. Use [Name.IsFullyQualified]
291	// to check if the name is fully qualified.
292	func (n Name) Filepath() string {
293		if !n.IsFullyQualified() {
294			panic("illegal attempt to get filepath of invalid name")
295		}
296		return filepath.Join(
297			n.Host,
298			n.Namespace,
299			n.Model,
300			n.Tag,
301		)
302	}
303	
304	// LogValue returns a slog.Value that represents the name as a string.
305	func (n Name) LogValue() slog.Value {
306		return slog.StringValue(n.String())
307	}
308	
309	func (n Name) EqualFold(o Name) bool {
310		return strings.EqualFold(n.Host, o.Host) &&
311			strings.EqualFold(n.Namespace, o.Namespace) &&
312			strings.EqualFold(n.Model, o.Model) &&
313			strings.EqualFold(n.Tag, o.Tag)
314	}
315	
316	// BaseURL returns the base URL for the registry.
317	func (n Name) BaseURL() *url.URL {
318		return &url.URL{
319			Scheme: n.ProtocolScheme,
320			Host:   n.Host,
321		}
322	}
323	
324	// DisplayNamespaceModel returns the namespace and model joined by "/".
325	func (n Name) DisplayNamespaceModel() string {
326		var b strings.Builder
327		b.WriteString(n.Namespace)
328		b.WriteByte('/')
329		b.WriteString(n.Model)
330		return b.String()
331	}
332	
333	func isValidLen(kind partKind, s string) bool {
334		switch kind {
335		case kindHost:
336			return len(s) >= 1 && len(s) <= 350
337		case kindTag:
338			return len(s) >= 1 && len(s) <= 80
339		default:
340			return len(s) >= 1 && len(s) <= 80
341		}
342	}
343	
344	func isValidPart(kind partKind, s string) bool {
345		if !isValidLen(kind, s) {
346			return false
347		}
348		for i := range s {
349			if i == 0 {
350				if !isAlphanumericOrUnderscore(s[i]) {
351					return false
352				}
353				continue
354			}
355			switch s[i] {
356			case '_', '-':
357			case '.':
358				if kind == kindNamespace {
359					return false
360				}
361			case ':':
362				if kind != kindHost && kind != kindDigest {
363					return false
364				}
365			default:
366				if !isAlphanumericOrUnderscore(s[i]) {
367					return false
368				}
369			}
370		}
371		return true
372	}
373	
374	func isAlphanumericOrUnderscore(c byte) bool {
375		return c >= 'A' && c <= 'Z' || c >= 'a' && c <= 'z' || c >= '0' && c <= '9' || c == '_'
376	}
377	
378	func cutLast(s, sep string) (before, after string, ok bool) {
379		i := strings.LastIndex(s, sep)
380		if i >= 0 {
381			return s[:i], s[i+len(sep):], true
382		}
383		return s, "", false
384	}
385	
386	// cutPromised cuts the last part of s at the last occurrence of sep. If sep is
387	// found, the part before and after sep are returned as-is unless empty, in
388	// which case they are returned as MissingPart, which will cause
389	// [Name.IsValid] to return false.
390	func cutPromised(s, sep string) (before, after string, ok bool) {
391		before, after, ok = cutLast(s, sep)
392		if !ok {
393			return before, after, false
394		}
395		return cmp.Or(before, MissingPart), cmp.Or(after, MissingPart), true
396	}
