1	package modelref
2	
3	import (
4		"errors"
5		"fmt"
6		"strings"
7	)
8	
9	type ModelSource uint8
10	
11	const (
12		ModelSourceUnspecified ModelSource = iota
13		ModelSourceLocal
14		ModelSourceCloud
15	)
16	
17	var (
18		ErrConflictingSourceSuffix = errors.New("use either :local or :cloud, not both")
19		ErrModelRequired           = errors.New("model is required")
20	)
21	
22	type ParsedRef struct {
23		Original string
24		Base     string
25		Source   ModelSource
26	}
27	
28	func ParseRef(raw string) (ParsedRef, error) {
29		var zero ParsedRef
30	
31		raw = strings.TrimSpace(raw)
32		if raw == "" {
33			return zero, ErrModelRequired
34		}
35	
36		base, source, explicit := parseSourceSuffix(raw)
37		if explicit {
38			if _, _, nested := parseSourceSuffix(base); nested {
39				return zero, fmt.Errorf("%w: %q", ErrConflictingSourceSuffix, raw)
40			}
41		}
42	
43		return ParsedRef{
44			Original: raw,
45			Base:     base,
46			Source:   source,
47		}, nil
48	}
49	
50	func HasExplicitCloudSource(raw string) bool {
51		parsedRef, err := ParseRef(raw)
52		return err == nil && parsedRef.Source == ModelSourceCloud
53	}
54	
55	func HasExplicitLocalSource(raw string) bool {
56		parsedRef, err := ParseRef(raw)
57		return err == nil && parsedRef.Source == ModelSourceLocal
58	}
59	
60	func StripCloudSourceTag(raw string) (string, bool) {
61		parsedRef, err := ParseRef(raw)
62		if err != nil || parsedRef.Source != ModelSourceCloud {
63			return strings.TrimSpace(raw), false
64		}
65	
66		return parsedRef.Base, true
67	}
68	
69	func NormalizePullName(raw string) (string, bool, error) {
70		parsedRef, err := ParseRef(raw)
71		if err != nil {
72			return "", false, err
73		}
74	
75		if parsedRef.Source != ModelSourceCloud {
76			return parsedRef.Base, false, nil
77		}
78	
79		return toLegacyCloudPullName(parsedRef.Base), true, nil
80	}
81	
82	func toLegacyCloudPullName(base string) string {
83		if hasExplicitTag(base) {
84			return base + "-cloud"
85		}
86	
87		return base + ":cloud"
88	}
89	
90	func hasExplicitTag(name string) bool {
91		lastSlash := strings.LastIndex(name, "/")
92		lastColon := strings.LastIndex(name, ":")
93		return lastColon > lastSlash
94	}
95	
96	func parseSourceSuffix(raw string) (string, ModelSource, bool) {
97		idx := strings.LastIndex(raw, ":")
98		if idx >= 0 {
99			suffixRaw := strings.TrimSpace(raw[idx+1:])
100			suffix := strings.ToLower(suffixRaw)
101	
102			switch suffix {
103			case "cloud":
104				return raw[:idx], ModelSourceCloud, true
105			case "local":
106				return raw[:idx], ModelSourceLocal, true
107			}
108	
109			if !strings.Contains(suffixRaw, "/") && strings.HasSuffix(suffix, "-cloud") {
110				return raw[:idx+1] + suffixRaw[:len(suffixRaw)-len("-cloud")], ModelSourceCloud, true
111			}
112		}
113	
114		return raw, ModelSourceUnspecified, false
115	}
116

96	func (c *Client) do(ctx context.Context, method, path string, reqData, respData any) error {
97		var reqBody io.Reader
98		var data []byte
99		var err error
100	
101		switch reqData := reqData.(type) {
102		case io.Reader:
103			// reqData is already an io.Reader
104			reqBody = reqData
105		case nil:
106			// noop
107		default:
108			data, err = json.Marshal(reqData)
109			if err != nil {
110				return err
111			}
112	
113			reqBody = bytes.NewReader(data)
114		}
115	
116		requestURL := c.base.JoinPath(path)
117	
118		var token string
119		if envconfig.UseAuth() || c.base.Hostname() == "ollama.com" {
120			now := strconv.FormatInt(time.Now().Unix(), 10)
121			chal := fmt.Sprintf("%s,%s?ts=%s", method, path, now)
122			token, err = getAuthorizationToken(ctx, chal)
123			if err != nil {
124				return err
125			}
126	
127			q := requestURL.Query()
128			q.Set("ts", now)
129			requestURL.RawQuery = q.Encode()
130		}
131	
132		request, err := http.NewRequestWithContext(ctx, method, requestURL.String(), reqBody)
133		if err != nil {
134			return err
135		}
136	
137		request.Header.Set("Content-Type", "application/json")
138		request.Header.Set("Accept", "application/json")
139		request.Header.Set("User-Agent", fmt.Sprintf("ollama/%s (%s %s) Go/%s", version.Version, runtime.GOARCH, runtime.GOOS, runtime.Version()))
140	
141		if token != "" {
142			request.Header.Set("Authorization", token)
143		}
