75		}
76	
77		blob, err := BlobsPath(digest)
78		if err != nil {
79			return Layer{}, err
80		}
81	
82		fi, err := os.Stat(blob)
83		if err != nil {
84			return Layer{}, err
85		}
86	
87		return Layer{
88			MediaType: mediatype,
89			Digest:    digest,
